import React from 'react';
import { useOrderContext } from '../../Cart_Page/contextAPI/OrderCartContext';
import CartItemCard from './Card'; 
import '../style/CartPage.css';

const CartPage = () => {
    const { order } = useOrderContext();

    // Calculate the total amount
    const totalCartAmount = Object.entries(order).reduce((total, [productId, quantity]) => {
        const item = menu.find((menuItem) => menuItem.name === productId);
        return item ? total + item.price * quantity : total;
    }, 0);

    return (
        <div className="cart-page">
            <h2>Your Cart</h2>
            <div className="cart-items">
                {Object.keys(order).length === 0 ? (
                    <p>Your cart is empty</p>
                ) : (
                    Object.entries(order).map(([productId, quantity]) => {
                        const item = menu.find((menuItem) => menuItem.name === productId);
                        return item ? (
                            <CartItemCard 
                                key={item._id}
                                name={item.item}
                                description={item.description}
                                price={item.price}
                                quantity={quantity}
                            />
                        ) : null;
                    })
                )}
            </div>
            <div className="cart-summary">
                <p>Total Amount: ${totalCartAmount.toFixed(2)}</p>
                <button onClick={() => alert("Proceeding to Payment...")} className="checkout-button">
                    Proceed to Payment
                </button>
            </div>
        </div>
    );
};

export default CartPage;
